const body = $input.item.json.body || {};
const qid  = String(body.quote_id || '').trim();
const resp = String(body.response || '').trim().toLowerCase();
const declineReason = (body.decline_reason || '').toString().slice(0, 500) || null;
if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(qid)) {
  return { json: { ok: false, status: 400, error: 'Invalid quote_id format' } };
}
if (resp !== 'accepted' && resp !== 'declined') {
  return { json: { ok: false, status: 400, error: 'response must be "accepted" or "declined"' } };
}
return { json: { quote_id: qid, response: resp, decline_reason: declineReason } };

const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    if (items.length === 1 && items[0] && typeof items[0] === 'object' && !Array.isArray(items[0]) && items[0].id) return [items[0]];
    return items.filter(function (x) { return x && x.id; });
  } catch (e) { return []; }
};
const rows = allOf('Fetch Quote');
const inp  = $('Validate Input').item.json;
if (rows.length === 0) {
  return { json: { ok: false, status: 404, error: 'Quote not found' } };
}
const q = rows[0];
// Expired check
const expired = q.expires_at && new Date(q.expires_at).getTime() < Date.now();
if (expired) return { json: { ok: false, status: 410, error: 'Quote has expired' } };

// Idempotency: same response repeated → return current state ok=true.
if (q.status === inp.response) {
  return { json: { ok: true, idempotent: true, quote_id: q.id, status: q.status, total_monthly_cents: q.total_monthly_cents, total_first_year_cents: q.total_first_year_cents } };
}
// Forbidden transition: anything already final (accepted/declined/expired) → no further change.
if (q.status === 'accepted' || q.status === 'declined' || q.status === 'expired') {
  return { json: { ok: false, status: 409, error: 'Quote already ' + q.status + '; cannot change to ' + inp.response } };
}
const now = new Date().toISOString();
const patch = { status: inp.response };
if (inp.response === 'accepted') {
  patch.accepted_at  = now;
} else {
  patch.declined_at  = now;
  patch.decline_reason = inp.decline_reason;
}
return { json: {
  ok: true,
  needs_patch: true,
  quote_id: q.id,
  patch: patch,
  quote_snapshot: { email: q.email, full_name: q.full_name, total_monthly_cents: q.total_monthly_cents, total_first_year_cents: q.total_first_year_cents },
  new_status: inp.response
} };

const d = $('Decide Action').first().json;
return { json: {
  ok: true,
  quote_id: d.quote_id,
  status: d.new_status,
  total_monthly_cents:    d.quote_snapshot.total_monthly_cents,
  total_first_year_cents: d.quote_snapshot.total_first_year_cents,
  message: d.new_status === 'accepted'
    ? 'Quote accepted. Mary (info@crystallux.org) will reach out to start onboarding.'
    : 'Quote declined. Thanks for the feedback.'
} };
